#include<bits/stdc++.h>
using namespace std;

long long n, m;
long long b[101][101], ans[101][101];

int main() {
	cin >> n >> m;
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < m; j++) {
			cin >> b[i][j];
		}
	}
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < m; j++) {
			for (int x = 0; x < n; x++) {
				for (int y = 0; y < m; y++) {
					if (b[i][j] == b[x][y]) {
                        if(ans[i][j]<=(i - x) * (i - x) + (j - y) * (j - y)){
                            ans[i][j]=(i - x) * (i - x) + (j - y) * (j - y);
                        }

					}
				}
			}
		}
	}for (int i = 0; i < n; i++) {
			for (int j = 0; j < m; j++) {
				cout<<ans[i][j]<<" ";
			}cout<<endl;
		}
	return 0;
}
